N = int(input())

books = [input().strip().split(', ') for i in range(N)]

def is_available(book):
    return book[1] == 'available'

def to_uppercase(book):
    return book[0].upper()

available_books = filter(is_available, books)
uppercase_titles = list(map(to_uppercase, available_books))

print(uppercase_titles)
